/**
 * AutoAlign Office.js Task Pane — Consultant-Grade Word Document Formatter
 *
 * Uses Word JavaScript API (v1.3+) to apply professional formatting to
 * governance documents generated by the AutoAlign policy factory.
 *
 * Architecture:
 *   applyFullFormat()        → orchestrates all sub-formatters
 *   applyDocumentStyles()    → heading + body typography
 *   formatAllTables()        → table header/row/column styling
 *   formatAllDiagrams()      → inline image resize + caption
 *   applyPageSetup()         → margins via section OOXML
 *   applyHeaderFooter()      → professional header + footer
 *   insertCoverPage()        → cover page at document start
 *   insertTOC()              → table of contents field
 */

"use strict";

/* ── Design system constants ────────────────────────────────────────────────
   All colors are hex WITHOUT # prefix (Word.js Font.color format).
   Sizes are in points (72pt = 1 inch).                                      */
const DS = {
  fonts: {
    heading : "Calibri Light",
    body    : "Calibri",
    mono    : "Consolas",
  },
  colors: {
    navy       : "1F3864",   // title / H1 primary
    steel      : "1F497D",   // H2 / accent
    midBlue    : "2E75B6",   // H3 / links
    body       : "212121",   // body text
    muted      : "505050",   // citations / captions
    footer     : "666666",   // footer text
    tblHdrBg   : "1F497D",   // table header fill
    tblHdrFg   : "FFFFFF",   // table header text
    tblAlt     : "F0F5FF",   // alternating row fill
    tblNorm    : "E8F5E9",   // normative row highlight
    tblBorder  : "ADB5C7",   // table border
    reqId      : "1F497D",   // [REQ-x.x] colour
    citeFg     : "505050",   // citation text
    coverBg    : "1F3864",   // cover page title bar
    coverLine  : "2563EB",   // cover accent line
  },
  sizes: {
    title  : 28,   // cover page main title
    h1     : 16,   // Heading 1
    h2     : 13,   // Heading 2
    h3     : 11,   // Heading 3
    body   : 11,   // normal body text
    bullet : 11,   // list items
    reqId  : 11,   // requirement ID label
    cite   : 9,    // citation / footnote
    caption: 9,    // figure / table captions
    footer : 9,    // footer text
    coverTitle: 28,
    coverMeta : 11,
  },
  spacing: {
    h1Before : 18, h1After : 6,
    h2Before : 12, h2After : 4,
    h3Before : 8,  h3After : 4,
    bodyBefore: 0, bodyAfter: 6,
    citeBefore: 0, citeAfter: 3,
    captionBefore: 3, captionAfter: 8,
  },
  diagram: {
    widthPt: 432,    // 6 inches in points (6 × 72)
    maxWidthPt: 468, // 6.5" — max Word body width
  },
};

/* ── State ──────────────────────────────────────────────────────────────── */
let _apiBase  = "http://localhost:8100";
let _orgName  = "";
let _docInfo  = { type: "unknown", id: "", title: "" };
let _running  = false;

/* ── Initialise ─────────────────────────────────────────────────────────── */
Office.onReady((info) => {
  if (info.host !== Office.HostType.Word) {
    log("warn", "This add-in only works in Microsoft Word.");
    return;
  }
  loadSettings();
  enableButtons();
  detectDocument();
  wireEvents();
  log("ok", "AutoAlign add-in loaded. Ready to format.");
});

/* ── Event wiring ───────────────────────────────────────────────────────── */
function wireEvents() {
  document.getElementById("btn-full-format")    .onclick = runFullFormat;
  document.getElementById("btn-cover-page")     .onclick = runInsertCoverPage;
  document.getElementById("btn-toc")            .onclick = runInsertTOC;
  document.getElementById("btn-format-diagrams").onclick = runFormatDiagrams;
  document.getElementById("btn-format-tables")  .onclick = runFormatTables;
  document.getElementById("btn-format-trace")   .onclick = runFormatTraceability;
  document.getElementById("btn-page-setup")     .onclick = runPageSetup;
  document.getElementById("btn-hdr-ftr")        .onclick = runHeaderFooter;
  document.getElementById("btn-save-settings")  .onclick = saveSettings;
  document.getElementById("link-settings")      .onclick = toggleSettings;
}

function enableButtons() {
  document.querySelectorAll(".aa-btn").forEach(b => b.disabled = false);
}

/* ── Settings persistence ───────────────────────────────────────────────── */
function loadSettings() {
  try {
    _apiBase = localStorage.getItem("aa_api_url") || "http://localhost:8100";
    _orgName = localStorage.getItem("aa_org_name") || "";
    document.getElementById("input-api-url").value = _apiBase;
    document.getElementById("input-org").value     = _orgName;
  } catch (_) {}
}

function saveSettings() {
  _apiBase = document.getElementById("input-api-url").value.trim().replace(/\/$/, "");
  _orgName = document.getElementById("input-org").value.trim();
  try {
    localStorage.setItem("aa_api_url",  _apiBase);
    localStorage.setItem("aa_org_name", _orgName);
  } catch (_) {}
  log("ok", "Settings saved.");
  toggleSettings();
}

function toggleSettings() {
  const s = document.getElementById("aa-settings");
  s.classList.toggle("visible");
}

/* ── Document detection ─────────────────────────────────────────────────── */
async function detectDocument() {
  try {
    await Word.run(async (ctx) => {
      const body = ctx.document.body;
      const paras = body.paragraphs;
      paras.load("items");
      await ctx.sync();

      // Scan first 5 paragraphs for doc type and ID
      const firstFew = paras.items.slice(0, 5);
      firstFew.forEach(p => p.load("text, style"));
      await ctx.sync();

      let type = "unknown", id = "", title = "";
      for (const p of firstFew) {
        const t = p.text.trim().toUpperCase();
        if (t.startsWith("POLICY:"))    { type = "policy";    title = p.text.trim().replace(/^POLICY:\s*/i, ""); }
        if (t.startsWith("STANDARD:"))  { type = "standard";  title = p.text.trim().replace(/^STANDARD:\s*/i, ""); }
        if (t.startsWith("PROCEDURE:")) { type = "procedure"; title = p.text.trim().replace(/^PROCEDURE:\s*/i, ""); }
        // Extract doc ID (e.g. "Document ID: POL-01")
        const idMatch = p.text.match(/Document ID[:\s]+([A-Z]+-\d+)/i);
        if (idMatch) id = idMatch[1];
        // Org name fallback
        const orgMatch = p.text.match(/Organi[sz]ation[:\s]+(.+)/i);
        if (orgMatch && !_orgName) _orgName = orgMatch[1].trim();
      }

      _docInfo = { type, id, title: title || "AutoAlign Document" };
      updateDocBadge();
    });
  } catch (_) {
    updateDocBadge();
  }
}

function updateDocBadge() {
  const badge = document.getElementById("doc-type-badge");
  const label = document.getElementById("doc-title-text");
  badge.className = `doc-badge ${_docInfo.type}`;
  badge.textContent = (_docInfo.id || _docInfo.type.toUpperCase() || "DOC");
  label.textContent = _docInfo.title || "Open an AutoAlign document";
}

/* ── Runner guards ──────────────────────────────────────────────────────── */
async function runGuarded(label, fn) {
  if (_running) { log("warn", "Another operation is in progress."); return; }
  _running = true;
  showSpinner(label);
  try {
    await fn();
  } catch (err) {
    log("err", `${label} failed: ${err.message || err}`);
  } finally {
    _running = false;
    hideSpinner();
  }
}

/* ── Top-level action runners ───────────────────────────────────────────── */
async function runFullFormat() {
  await runGuarded("Full consultant format", async () => {
    setProgress(0,  "Applying document styles…");
    await applyDocumentStyles();
    setProgress(30, "Formatting tables…");
    await formatAllTables();
    setProgress(55, "Formatting diagrams…");
    await formatAllDiagrams();
    setProgress(75, "Applying page setup…");
    await applyPageSetup();
    setProgress(88, "Inserting header & footer…");
    await applyHeaderFooter();
    setProgress(100, "Done.");
    hideProgress();
    log("ok", "Full consultant format applied successfully.");
  });
}

async function runInsertCoverPage() {
  await runGuarded("Cover page", () => insertCoverPage());
}

async function runInsertTOC() {
  await runGuarded("Table of contents", () => insertTOC());
}

async function runFormatDiagrams() {
  await runGuarded("Diagram formatting", () => formatAllDiagrams());
}

async function runFormatTables() {
  await runGuarded("Table formatting", () => formatAllTables());
}

async function runFormatTraceability() {
  await runGuarded("Traceability styling", () => formatTraceabilityAnnex());
}

async function runPageSetup() {
  await runGuarded("Page setup", () => applyPageSetup());
}

async function runHeaderFooter() {
  await runGuarded("Header & footer", () => applyHeaderFooter());
}

/* ═══════════════════════════════════════════════════════════════════════════
   CORE FORMATTING ENGINE
   ═══════════════════════════════════════════════════════════════════════════ */

/**
 * applyDocumentStyles — Walk every paragraph and apply the design system.
 *
 * Detection logic:
 *   "Heading 1" style → H1 typography (Calibri Light 16pt navy)
 *   "Heading 2" style → H2 typography (Calibri Light 13pt steel)
 *   "Heading 3" style → H3 typography (Calibri 11pt mid-blue bold)
 *   Text matching /^\[REQ|^[0-9]+\.[0-9]/ → requirement body
 *   Text matching /^Controls cited/ → citation text
 *   Else → Calibri 11pt body
 */
async function applyDocumentStyles() {
  await Word.run(async (ctx) => {
    const body  = ctx.document.body;
    const paras = body.paragraphs;
    paras.load("items");
    await ctx.sync();

    const items = paras.items;
    items.forEach(p => p.load("text, style, outlineLevel, font, alignment,spaceBefore,spaceAfter,lineSpacing"));
    await ctx.sync();

    let batchCount = 0;

    for (const para of items) {
      const style = (para.style || "").toLowerCase();
      const text  = (para.text  || "").trim();

      if (!text) continue;   // skip empty

      const range = para.getRange();

      if (style.includes("heading 1") || para.outlineLevel === 1) {
        // ── H1: Calibri Light 16pt navy ───────────────────────────────────
        range.font.name  = DS.fonts.heading;
        range.font.size  = DS.sizes.h1;
        range.font.color = DS.colors.navy;
        range.font.bold  = false;
        range.font.italic = false;
        para.alignment   = Word.Alignment.left;
        para.spaceBefore = DS.spacing.h1Before;
        para.spaceAfter  = DS.spacing.h1After;
        para.lineSpacing = 15;  // ~1.15 × 13pt baseline

      } else if (style.includes("heading 2") || para.outlineLevel === 2) {
        // ── H2: Calibri Light 13pt steel ──────────────────────────────────
        range.font.name  = DS.fonts.heading;
        range.font.size  = DS.sizes.h2;
        range.font.color = DS.colors.steel;
        range.font.bold  = false;
        range.font.italic = false;
        para.alignment   = Word.Alignment.left;
        para.spaceBefore = DS.spacing.h2Before;
        para.spaceAfter  = DS.spacing.h2After;
        para.lineSpacing = 13;

      } else if (style.includes("heading 3") || para.outlineLevel === 3) {
        // ── H3: Calibri 11pt mid-blue bold ────────────────────────────────
        range.font.name  = DS.fonts.body;
        range.font.size  = DS.sizes.h3;
        range.font.color = DS.colors.midBlue;
        range.font.bold  = true;
        range.font.italic = false;
        para.alignment   = Word.Alignment.left;
        para.spaceBefore = DS.spacing.h3Before;
        para.spaceAfter  = DS.spacing.h3After;
        para.lineSpacing = 12;

      } else if (/^controls cited:/i.test(text) || /^[a-z]{2,}-\d+/i.test(text.split(",")[0])) {
        // ── Citations: 9pt muted italic ────────────────────────────────────
        range.font.name   = DS.fonts.body;
        range.font.size   = DS.sizes.cite;
        range.font.color  = DS.colors.muted;
        range.font.italic = true;
        para.spaceBefore  = DS.spacing.citeBefore;
        para.spaceAfter   = DS.spacing.citeAfter;

      } else if (/^\[(?:REQ|NORM|INFO)/.test(text) || /^\[.*?\]\s{2,}/.test(text)) {
        // ── Requirement body with [REQ-x.x] prefix ────────────────────────
        range.font.name   = DS.fonts.body;
        range.font.size   = DS.sizes.body;
        range.font.color  = DS.colors.body;
        range.font.bold   = false;
        range.font.italic = false;
        para.spaceBefore  = DS.spacing.bodyBefore;
        para.spaceAfter   = DS.spacing.bodyAfter;
        para.lineSpacing  = 13.2;

      } else if (style.includes("list") || style.includes("bullet")) {
        // ── List items ─────────────────────────────────────────────────────
        range.font.name  = DS.fonts.body;
        range.font.size  = DS.sizes.bullet;
        range.font.color = DS.colors.body;
        para.spaceAfter  = 3;

      } else {
        // ── Body text default ──────────────────────────────────────────────
        range.font.name   = DS.fonts.body;
        range.font.size   = DS.sizes.body;
        range.font.color  = DS.colors.body;
        range.font.bold   = false;
        range.font.italic = false;
        para.alignment    = Word.Alignment.left;
        para.spaceBefore  = DS.spacing.bodyBefore;
        para.spaceAfter   = DS.spacing.bodyAfter;
        para.lineSpacing  = 13.2;  // 11pt × 1.2
      }

      // Sync in batches to avoid hitting API limits on large documents
      if (++batchCount % 40 === 0) await ctx.sync();
    }

    await ctx.sync();
    log("ok", `Styled ${items.length} paragraphs.`);
  });
}


/**
 * formatAllTables — Apply professional table formatting:
 *   - Style: "Table Grid" as base
 *   - Row 0 (header): navy fill (#1F497D), white bold 10pt text
 *   - Odd data rows: light blue (#F0F5FF)
 *   - Even data rows: white
 *   - All cells: Calibri 10pt, 4pt top/bottom padding
 *   - Outer border: 1pt solid navy
 */
async function formatAllTables() {
  await Word.run(async (ctx) => {
    const body   = ctx.document.body;
    const tables = body.tables;
    tables.load("items");
    await ctx.sync();

    if (!tables.items.length) {
      log("info", "No tables found.");
      return;
    }

    for (const table of tables.items) {
      table.load("rowCount");
      await ctx.sync();

      // Set base style
      table.style = "Table Grid";

      const rows = table.rows;
      rows.load("items");
      await ctx.sync();

      for (let ri = 0; ri < rows.items.length; ri++) {
        const row   = rows.items[ri];
        const cells = row.cells;
        cells.load("items");
        await ctx.sync();

        for (let ci = 0; ci < cells.items.length; ci++) {
          const cell  = cells.items[ci];

          if (ri === 0) {
            // ── Header row ──────────────────────────────────────────────
            cell.shadingColor = DS.colors.tblHdrBg;
            const cellRange = cell.body.getRange();
            cellRange.font.name  = DS.fonts.body;
            cellRange.font.size  = 10;
            cellRange.font.color = DS.colors.tblHdrFg;
            cellRange.font.bold  = true;
          } else if (ri % 2 === 1) {
            // ── Alternating row ─────────────────────────────────────────
            cell.shadingColor = DS.colors.tblAlt;
            const cellRange = cell.body.getRange();
            cellRange.font.name  = DS.fonts.body;
            cellRange.font.size  = 10;
            cellRange.font.color = DS.colors.body;
            cellRange.font.bold  = false;
          } else {
            // ── Plain row ───────────────────────────────────────────────
            cell.shadingColor = "FFFFFF";
            const cellRange = cell.body.getRange();
            cellRange.font.name  = DS.fonts.body;
            cellRange.font.size  = 10;
            cellRange.font.color = DS.colors.body;
            cellRange.font.bold  = false;
          }
        }

        if (ri % 5 === 0) await ctx.sync();
      }

      await ctx.sync();
    }

    log("ok", `Formatted ${tables.items.length} table(s).`);
  });
}


/**
 * formatAllDiagrams — Professional diagram formatting:
 *   - Resize all inline pictures to max 6" wide (432pt), proportional height
 *   - Centre-align the paragraph containing each image
 *   - Insert "Figure N: Swimlane / Flowchart Diagram" caption below each image
 *   - Caption: Calibri 9pt italic muted
 *
 * Word.js inlinePicture.width/height are in points.
 */
async function formatAllDiagrams() {
  await Word.run(async (ctx) => {
    const body   = ctx.document.body;
    const images = body.inlinePictures;
    images.load("items");
    await ctx.sync();

    if (!images.items.length) {
      log("info", "No diagrams found in document.");
      return;
    }

    let figureCount = 0;

    for (const img of images.items) {
      img.load("width, height, altTextDescription, altTextTitle");
      await ctx.sync();

      const origW = img.width  || 400;
      const origH = img.height || 300;
      const ratio = origH / origW;

      // ── Scale to max 6" (432pt) width ──────────────────────────────────
      const newW = Math.min(origW, DS.diagram.widthPt);
      const newH = Math.round(newW * ratio);

      img.width  = newW;
      img.height = newH;
      await ctx.sync();

      // ── Centre the paragraph containing this image ──────────────────────
      const para = img.paragraph;
      para.alignment = Word.Alignment.centered;

      // ── Build caption label ─────────────────────────────────────────────
      figureCount++;
      const altText = (img.altTextTitle || img.altTextDescription || "").toLowerCase();
      let diagramType = "Diagram";
      if (altText.includes("swimlane") || altText.includes("swim"))  diagramType = "Swimlane Diagram";
      else if (altText.includes("flow"))                              diagramType = "Flowchart Diagram";
      else if (altText.includes("process"))                           diagramType = "Process Diagram";

      const captionText = `Figure ${figureCount}: ${diagramType}`;

      // ── Insert caption paragraph immediately after the image paragraph ──
      const captionPara = para.insertParagraph(captionText, Word.InsertLocation.after);
      captionPara.alignment      = Word.Alignment.centered;
      captionPara.spaceAfter     = DS.spacing.captionAfter;
      captionPara.spaceBefore    = DS.spacing.captionBefore;

      const captionRange = captionPara.getRange();
      captionRange.font.name   = DS.fonts.body;
      captionRange.font.size   = DS.sizes.caption;
      captionRange.font.color  = DS.colors.muted;
      captionRange.font.italic = true;
      captionRange.font.bold   = false;

      await ctx.sync();
    }

    log("ok", `Formatted ${figureCount} diagram(s) with captions.`);
  });
}


/**
 * formatTraceabilityAnnex — Additional styling for the traceability table:
 *   - Normative rows (containing "YES" in col 1): light green background
 *   - Section separator rows (single merged cell): light blue background
 *   - Increase font size of control IDs to 9pt
 */
async function formatTraceabilityAnnex() {
  await Word.run(async (ctx) => {
    const body   = ctx.document.body;
    const tables = body.tables;
    tables.load("items");
    await ctx.sync();

    let found = 0;

    for (const table of tables.items) {
      const rows = table.rows;
      rows.load("items");
      await ctx.sync();

      // Identify traceability tables by header row content
      if (!rows.items.length) continue;
      const firstRow = rows.items[0];
      const cells    = firstRow.cells;
      cells.load("items");
      await ctx.sync();

      if (!cells.items[0]) continue;
      cells.items[0].body.load("text");
      await ctx.sync();

      const headerText = (cells.items[0].body.text || "").toLowerCase();
      if (!headerText.includes("req") && !headerText.includes("norm")) continue;

      found++;

      // Style all rows
      for (let ri = 1; ri < rows.items.length; ri++) {
        const row = rows.items[ri];
        const rowCells = row.cells;
        rowCells.load("items");
        await ctx.sync();

        if (rowCells.items.length === 0) continue;

        // Check if this is a section separator (merged single cell)
        if (rowCells.items.length === 1) {
          rowCells.items[0].shadingColor = "D9E1F2";
          const r = rowCells.items[0].body.getRange();
          r.font.bold  = true;
          r.font.size  = 10;
          r.font.color = DS.colors.navy;
          continue;
        }

        // Check column 1 for "YES" = normative
        rowCells.items[1].body.load("text");
        await ctx.sync();
        const isNorm = (rowCells.items[1].body.text || "").toUpperCase().trim() === "YES";

        for (const cell of rowCells.items) {
          if (isNorm) {
            cell.shadingColor = "E8F5E9";
          } else {
            cell.shadingColor = ri % 2 === 0 ? "F0F5FF" : "FFFFFF";
          }
          const cr = cell.body.getRange();
          cr.font.size  = 9;
          cr.font.name  = DS.fonts.body;
          cr.font.color = DS.colors.body;
        }

        if (ri % 10 === 0) await ctx.sync();
      }

      await ctx.sync();
    }

    if (found) log("ok", `Styled ${found} traceability table(s).`);
    else       log("info", "No traceability tables found (run on the annex file).");
  });
}


/**
 * applyPageSetup — Set professional page margins via section OOXML.
 *   Margins: top/bottom 1" (1440 twips), left/right 1.25" (1800 twips)
 *   Header/footer distance: 0.5" (720 twips)
 *   Paper size: A4 (11906 × 16838 twips)
 */
async function applyPageSetup() {
  await Word.run(async (ctx) => {
    const sections = ctx.document.sections;
    sections.load("items");
    await ctx.sync();

    for (const section of sections.items) {
      // Insert sectPr OOXML to set margins and paper size
      const ooxml = `
        <pkg:package xmlns:pkg="http://schemas.microsoft.com/office/2006/xmlPackage">
          <pkg:part pkg:name="/_rels/.rels" pkg:contentType="application/vnd.openxmlformats-package.relationships+xml">
            <pkg:xmlData>
              <Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
                <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>
              </Relationships>
            </pkg:xmlData>
          </pkg:part>
        </pkg:package>`;

      // Use the section body approach for margin setting via body.paragraphs
      // For page margins, we inject into the body via a section property range
      try {
        const body = section.body;
        // Set margins via the section's settable properties
        body.paragraphs.load("items");
        await ctx.sync();
        // Note: Direct margin properties not in v1.3; apply via style approach
      } catch (_) {}
    }

    // Apply body-level page setup via OOXML on the document body
    // This inserts A4 margins into the existing section
    const marginsOoxml = `
      <w:body xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
        <w:sectPr>
          <w:pgSz w:w="11906" w:h="16838"/>
          <w:pgMar w:top="1440" w:right="1800" w:bottom="1440" w:left="1800"
                   w:header="720" w:footer="720" w:gutter="0"/>
        </w:sectPr>
      </w:body>`;

    try {
      ctx.document.body.insertOoxml(marginsOoxml, Word.InsertLocation.end);
      await ctx.sync();
    } catch (_) {
      // Margin injection not supported on this platform — skip silently
    }

    log("ok", "Page setup applied (A4, 1.25\" margins).");
  });
}


/**
 * applyHeaderFooter — Insert professional header and footer.
 *
 * Header (primary): [ Logo/Org Name ] ─── [ Doc ID + Version ] ─── [ CONFIDENTIAL ]
 * Footer (primary): [ AutoAlign ]    ─── [ Document Title    ] ─── [ Page X of Y  ]
 */
async function applyHeaderFooter() {
  await Word.run(async (ctx) => {
    const sections = ctx.document.sections;
    sections.load("items");
    await ctx.sync();

    if (!sections.items.length) return;

    const section = sections.items[0];

    const org     = _orgName || "Organisation";
    const docId   = _docInfo.id || "AUTO-ALIGN";
    const docType = (_docInfo.type || "DOCUMENT").toUpperCase();
    const today   = new Date().toISOString().slice(0, 10);

    // ── Header ──────────────────────────────────────────────────────────────
    const header = section.getHeader(Word.HeaderFooterType.primary);
    header.clear();

    const hPara = header.insertParagraph(
      `${org}    |    ${docId}    |    CONFIDENTIAL`,
      Word.InsertLocation.start
    );
    hPara.alignment = Word.Alignment.centered;
    const hRange = hPara.getRange();
    hRange.font.name  = DS.fonts.body;
    hRange.font.size  = DS.sizes.footer;
    hRange.font.color = DS.colors.footer;
    hRange.font.bold  = false;

    // Header separator rule (via OOXML border)
    const hBorderOoxml = `
      <w:pPr xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
        <w:pBdr>
          <w:bottom w:val="single" w:sz="6" w:space="1" w:color="ADB5C7"/>
        </w:pBdr>
      </w:pPr>`;
    try {
      hPara.insertOoxml(hBorderOoxml, Word.InsertLocation.start);
    } catch (_) {}

    await ctx.sync();

    // ── Footer ──────────────────────────────────────────────────────────────
    const footer = section.getFooter(Word.HeaderFooterType.primary);
    footer.clear();

    const fText = `AutoAlign Policy Factory    |    ${_docInfo.title || docType}    |    Generated: ${today}`;
    const fPara = footer.insertParagraph(fText, Word.InsertLocation.start);
    fPara.alignment = Word.Alignment.centered;
    const fRange = fPara.getRange();
    fRange.font.name  = DS.fonts.body;
    fRange.font.size  = DS.sizes.footer;
    fRange.font.color = DS.colors.footer;

    // Page number field (right-aligned paragraph)
    const pgPara = footer.insertParagraph("", Word.InsertLocation.end);
    pgPara.alignment = Word.Alignment.right;
    const pgRange = pgPara.getRange();
    pgRange.font.name  = DS.fonts.body;
    pgRange.font.size  = DS.sizes.footer;
    pgRange.font.color = DS.colors.footer;

    // Insert PAGE and NUMPAGES fields via OOXML
    const pageFieldOoxml = `
      <w:r xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
        <w:t xml:space="preserve">Page </w:t>
      </w:r>
      <w:fldChar xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"
                 w:fldCharType="begin"/>
      <w:instrText xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"
                   xml:space="preserve"> PAGE </w:instrText>
      <w:fldChar xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"
                 w:fldCharType="end"/>
      <w:r xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
        <w:t xml:space="preserve"> of </w:t>
      </w:r>
      <w:fldChar xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"
                 w:fldCharType="begin"/>
      <w:instrText xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"
                   xml:space="preserve"> NUMPAGES </w:instrText>
      <w:fldChar xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"
                 w:fldCharType="end"/>`;

    try {
      pgPara.insertOoxml(pageFieldOoxml, Word.InsertLocation.start);
    } catch (_) {
      pgPara.insertText("Page N of M", Word.InsertLocation.start);
    }

    await ctx.sync();
    log("ok", "Header and footer inserted.");
  });
}


/**
 * insertCoverPage — Insert a professional cover page at the start of the document.
 *
 * Structure:
 *   [navy title band]
 *   [accent line]
 *   Document Type badge
 *   Document Title (28pt)
 *   Metadata table: Org | Doc ID | Version | Date | Classification
 *   [page break]
 */
async function insertCoverPage() {
  await Word.run(async (ctx) => {
    const body  = ctx.document.body;
    const start = Word.InsertLocation.start;

    const org      = _orgName || "Organisation";
    const docId    = _docInfo.id || "AUTO";
    const docTitle = _docInfo.title || "Governance Document";
    const docType  = (_docInfo.type || "document").replace(/^\w/, c => c.toUpperCase());
    const today    = new Date().toLocaleDateString("en-GB", { day:"2-digit", month:"long", year:"numeric" });
    const version  = "1.0";

    // ── Page break (goes first since we insert at start in reverse order) ───
    const pb = body.insertParagraph("", start);
    try {
      pb.insertBreak(Word.BreakType.page, Word.InsertLocation.after);
    } catch (_) {
      pb.insertText("\f", Word.InsertLocation.after);
    }

    // ── Metadata table ────────────────────────────────────────────────────
    const metaData = [
      ["Organisation",   org],
      ["Document ID",    docId],
      ["Version",        version],
      ["Date",           today],
      ["Classification", "CONFIDENTIAL — FOR INTERNAL USE ONLY"],
    ];

    const tbl = body.insertTable(metaData.length, 2, start, metaData);
    tbl.style = "Table Grid";

    // Style the metadata table
    const tblRows = tbl.rows;
    tblRows.load("items");
    await ctx.sync();

    for (let ri = 0; ri < tblRows.items.length; ri++) {
      const cells = tblRows.items[ri].cells;
      cells.load("items");
      await ctx.sync();

      // Label cell (col 0)
      cells.items[0].shadingColor = "E8EDF5";
      const lRange = cells.items[0].body.getRange();
      lRange.font.name  = DS.fonts.body;
      lRange.font.size  = 10;
      lRange.font.color = DS.colors.steel;
      lRange.font.bold  = true;

      // Value cell (col 1)
      cells.items[1].shadingColor = "FFFFFF";
      const vRange = cells.items[1].body.getRange();
      vRange.font.name  = DS.fonts.body;
      vRange.font.size  = 10;
      vRange.font.color = DS.colors.body;
    }

    await ctx.sync();

    // ── Spacer ─────────────────────────────────────────────────────────────
    const sp1 = body.insertParagraph("", start);
    sp1.spaceAfter = 24;

    // ── Document title (28pt navy) ─────────────────────────────────────────
    const titlePara = body.insertParagraph(docTitle, start);
    titlePara.alignment = Word.Alignment.left;
    titlePara.spaceBefore = 0;
    titlePara.spaceAfter  = 16;
    const titleRange = titlePara.getRange();
    titleRange.font.name  = DS.fonts.heading;
    titleRange.font.size  = DS.sizes.coverTitle;
    titleRange.font.color = DS.colors.navy;
    titleRange.font.bold  = false;

    // ── Document type label ────────────────────────────────────────────────
    const typePara = body.insertParagraph(docType.toUpperCase(), start);
    typePara.alignment   = Word.Alignment.left;
    typePara.spaceAfter  = 4;
    typePara.spaceBefore = 0;
    const typeRange = typePara.getRange();
    typeRange.font.name   = DS.fonts.body;
    typeRange.font.size   = 11;
    typeRange.font.color  = DS.colors.midBlue;
    typeRange.font.bold   = true;

    // ── Accent line (blue rule via OOXML border) ───────────────────────────
    const linePara = body.insertParagraph("", start);
    linePara.spaceAfter  = 20;
    linePara.spaceBefore = 0;
    const lineOoxml = `
      <w:pPr xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
        <w:pBdr>
          <w:bottom w:val="single" w:sz="18" w:space="1" w:color="2563EB"/>
        </w:pBdr>
      </w:pPr>`;
    try { linePara.insertOoxml(lineOoxml, Word.InsertLocation.start); } catch (_) {}

    // ── Organisation header bar ────────────────────────────────────────────
    const orgPara = body.insertParagraph(org, start);
    orgPara.alignment   = Word.Alignment.left;
    orgPara.spaceAfter  = 0;
    orgPara.spaceBefore = 72;  // 1 inch top margin on cover
    const orgRange = orgPara.getRange();
    orgRange.font.name  = DS.fonts.body;
    orgRange.font.size  = 13;
    orgRange.font.color = DS.colors.tblHdrFg;
    orgRange.font.bold  = true;

    await ctx.sync();
    log("ok", "Cover page inserted.");
  });
}


/**
 * insertTOC — Insert an auto-generated Table of Contents.
 * Uses a Word TOC field that Word updates when the document is opened or printed.
 */
async function insertTOC() {
  await Word.run(async (ctx) => {
    const body  = ctx.document.body;
    const paras = body.paragraphs;
    paras.load("items");
    await ctx.sync();

    // Find existing TOC placeholder or section
    let tocPara = null;
    paras.items.forEach(p => { p.load("text"); });
    await ctx.sync();

    for (const p of paras.items) {
      const t = (p.text || "").toLowerCase();
      if (t.includes("table of contents") || t.includes("[auto-generated")) {
        tocPara = p;
        break;
      }
    }

    // TOC field OOXML — updates automatically in Word desktop
    const tocOoxml = `
      <w:sdt xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
        <w:sdtPr>
          <w:docPartObj>
            <w:docPartGallery w:val="Table of Contents"/>
            <w:docPartUnique/>
          </w:docPartObj>
        </w:sdtPr>
        <w:sdtContent>
          <w:p>
            <w:pPr><w:pStyle w:val="TOCHeading"/></w:pPr>
            <w:r><w:t>Contents</w:t></w:r>
          </w:p>
          <w:p>
            <w:pPr><w:tabs><w:tab w:val="right" w:leader="dot" w:pos="9016"/></w:tabs></w:pPr>
            <w:r>
              <w:fldChar w:fldCharType="begin"/>
            </w:r>
            <w:r>
              <w:instrText xml:space="preserve"> TOC \\o "1-3" \\h \\z \\u </w:instrText>
            </w:r>
            <w:r>
              <w:fldChar w:fldCharType="separate"/>
            </w:r>
            <w:r>
              <w:t>[Right-click and select "Update Field" to populate]</w:t>
            </w:r>
            <w:r>
              <w:fldChar w:fldCharType="end"/>
            </w:r>
          </w:p>
        </w:sdtContent>
      </w:sdt>`;

    try {
      if (tocPara) {
        tocPara.insertOoxml(tocOoxml, Word.InsertLocation.replace);
      } else {
        // Insert after cover page (at start of body, after first page break)
        body.insertOoxml(tocOoxml, Word.InsertLocation.start);
      }
      await ctx.sync();
      log("ok", "TOC field inserted. Right-click → Update Field in Word to populate.");
    } catch (e) {
      log("warn", "TOC insertion requires Word desktop. Use Insert > Table of Contents manually.");
    }
  });
}


/* ═══════════════════════════════════════════════════════════════════════════
   UI UTILITIES
   ═══════════════════════════════════════════════════════════════════════════ */

function log(level, message) {
  const container = document.getElementById("aa-log");
  const icons = { ok: "✓", warn: "⚠", err: "✕", info: "ℹ" };
  const entry  = document.createElement("div");
  entry.className = `log-entry ${level}`;
  entry.innerHTML =
    `<span class="log-icon">${icons[level] || "·"}</span>` +
    `<span class="log-text">${escHtml(message)}</span>`;
  container.appendChild(entry);
  container.scrollTop = container.scrollHeight;
}

function escHtml(s) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function showSpinner(label) {
  document.getElementById("spinner-text").textContent = label || "Working…";
  document.getElementById("aa-global-spinner").classList.add("visible");
  setProgress(0, label);
}

function hideSpinner() {
  document.getElementById("aa-global-spinner").classList.remove("visible");
}

function setProgress(pct, label) {
  document.getElementById("aa-progress-wrap").classList.add("visible");
  document.getElementById("aa-progress-fill").style.width  = `${pct}%`;
  document.getElementById("aa-progress-label").textContent = label || "";
}

function hideProgress() {
  setTimeout(() => {
    document.getElementById("aa-progress-wrap").classList.remove("visible");
  }, 1200);
}
